create table dirkspzm32.pe_drucker_layout_cfg (
    sid               varchar2(2 char) not null enable,
    firma_nr          number(6, 0) not null enable,
    drucker_name      varchar2(255 char) not null enable,
    src_layout_name   varchar2(100 char) not null enable,
    src_layout_datei  varchar2(255 char),
    etiketten_name    varchar2(50 char),
    dest_layout_name  varchar2(100 char) not null enable,
    dest_layout_datei varchar2(255 char),
    dest_anzahl       number(*, 0)
);

alter table dirkspzm32.pe_drucker_layout_cfg
    add constraint pk_pe_drucker_layout_cfg
        primary key ( drucker_name,
                      src_layout_name,
                      firma_nr,
                      sid )
            using index enable;


